@Test public void matchTextWithAttribute() {
    String html = "<div><p id='test'>One<br>Two</p></div>";
    Document doc = Jsoup.parse(html);
    Elements els = doc.select("p[id]:matchText");
    assertEquals(2, els.size());
    assertEquals("One", els.get(0).text());
    assertEquals("Two", els.get(1).text());
}

@Test public void matchTextWithCombinator() {
    String html = "<div><p>One<br>Two</p><span>Three</span></div>";
    Document doc = Jsoup.parse(html);
    Elements els = doc.select("p:matchText ~ span");
    assertEquals(1, els.size());
    assertEquals("Three", els.first().text());
}

@Test public void matchTextNthChild() {
    String html = "<div><p>A<br>B<br>C</p></div>";
    Document doc = Jsoup.parse(html);
    Elements els = doc.select("p:matchText:nth-child(2)");
    assertEquals(1, els.size());
    assertEquals("B", els.first().text());
}
